-- Tenant-scoped relations must carry the tenant on both sides of every foreign key.
DO $$
DECLARE target text;
BEGIN
  FOREACH target IN ARRAY ARRAY[
    'organizations','sites','customers','assets','service_offerings','availability_slots','bookings',
    'passports','passport_entries','asset_deadlines','documents','consents','document_share_grants',
    'crm_pipelines','crm_opportunities','notification_templates','notifications','workflow_definitions',
    'workflow_instances','workflow_work_items','quotes','sales_orders','invoices','payments','work_orders','parts',
    'passport_qr_grants','reminders','crm_tasks','consents','document_share_grants',
    'disclosure_logs','payment_refunds','bank_transactions','stock_reservations','purchase_orders'
  ] LOOP
    EXECUTE format('CREATE UNIQUE INDEX IF NOT EXISTS %I ON %I (tenant_id,id)', target || '_tenant_id_id_uidx', target);
  END LOOP;
END $$;

ALTER TABLE sites DROP CONSTRAINT sites_organization_id_fkey, ADD CONSTRAINT sites_tenant_organization_fk FOREIGN KEY(tenant_id,organization_id) REFERENCES organizations(tenant_id,id);
ALTER TABLE memberships DROP CONSTRAINT memberships_organization_id_fkey, ADD CONSTRAINT memberships_tenant_organization_fk FOREIGN KEY(tenant_id,organization_id) REFERENCES organizations(tenant_id,id);
ALTER TABLE customers DROP CONSTRAINT customers_acquisition_owner_organization_id_fkey, ADD CONSTRAINT customers_tenant_acquisition_owner_fk FOREIGN KEY(tenant_id,acquisition_owner_organization_id) REFERENCES organizations(tenant_id,id);
ALTER TABLE assets DROP CONSTRAINT assets_owner_customer_id_fkey, ADD CONSTRAINT assets_tenant_owner_fk FOREIGN KEY(tenant_id,owner_customer_id) REFERENCES customers(tenant_id,id);
