ALTER TABLE availability_slots DROP CONSTRAINT availability_slots_offering_id_fkey, DROP CONSTRAINT availability_slots_site_id_fkey, ADD CONSTRAINT slots_tenant_offering_fk FOREIGN KEY(tenant_id,offering_id) REFERENCES service_offerings(tenant_id,id), ADD CONSTRAINT slots_tenant_site_fk FOREIGN KEY(tenant_id,site_id) REFERENCES sites(tenant_id,id);
ALTER TABLE bookings DROP CONSTRAINT bookings_organization_id_fkey, DROP CONSTRAINT bookings_site_id_fkey, DROP CONSTRAINT bookings_offering_id_fkey, DROP CONSTRAINT bookings_slot_id_fkey, DROP CONSTRAINT bookings_customer_id_fkey, DROP CONSTRAINT bookings_asset_id_fkey, DROP CONSTRAINT bookings_acquisition_owner_organization_id_fkey, ADD CONSTRAINT bookings_tenant_organization_fk FOREIGN KEY(tenant_id,organization_id) REFERENCES organizations(tenant_id,id), ADD CONSTRAINT bookings_tenant_site_fk FOREIGN KEY(tenant_id,site_id) REFERENCES sites(tenant_id,id), ADD CONSTRAINT bookings_tenant_offering_fk FOREIGN KEY(tenant_id,offering_id) REFERENCES service_offerings(tenant_id,id), ADD CONSTRAINT bookings_tenant_slot_fk FOREIGN KEY(tenant_id,slot_id) REFERENCES availability_slots(tenant_id,id), ADD CONSTRAINT bookings_tenant_customer_fk FOREIGN KEY(tenant_id,customer_id) REFERENCES customers(tenant_id,id), ADD CONSTRAINT bookings_tenant_asset_fk FOREIGN KEY(tenant_id,asset_id) REFERENCES assets(tenant_id,id), ADD CONSTRAINT bookings_tenant_acquisition_owner_fk FOREIGN KEY(tenant_id,acquisition_owner_organization_id) REFERENCES organizations(tenant_id,id);
