ALTER TABLE crm_opportunities DROP CONSTRAINT crm_opportunities_organization_id_fkey, DROP CONSTRAINT crm_opportunities_site_id_fkey, DROP CONSTRAINT crm_opportunities_pipeline_id_fkey, DROP CONSTRAINT crm_opportunities_customer_id_fkey, DROP CONSTRAINT crm_opportunities_asset_id_fkey, ADD CONSTRAINT crm_opportunities_tenant_organization_fk FOREIGN KEY(tenant_id,organization_id) REFERENCES organizations(tenant_id,id), ADD CONSTRAINT crm_opportunities_tenant_site_fk FOREIGN KEY(tenant_id,site_id) REFERENCES sites(tenant_id,id), ADD CONSTRAINT crm_opportunities_tenant_pipeline_fk FOREIGN KEY(tenant_id,pipeline_id) REFERENCES crm_pipelines(tenant_id,id), ADD CONSTRAINT crm_opportunities_tenant_customer_fk FOREIGN KEY(tenant_id,customer_id) REFERENCES customers(tenant_id,id), ADD CONSTRAINT crm_opportunities_tenant_asset_fk FOREIGN KEY(tenant_id,asset_id) REFERENCES assets(tenant_id,id);
