ALTER TABLE passport_entries DROP CONSTRAINT passport_entries_passport_id_fkey, DROP CONSTRAINT passport_entries_asset_id_fkey, DROP CONSTRAINT passport_entries_provider_organization_id_fkey, ADD CONSTRAINT passport_entries_tenant_passport_fk FOREIGN KEY(tenant_id,passport_id) REFERENCES passports(tenant_id,id), ADD CONSTRAINT passport_entries_tenant_asset_fk FOREIGN KEY(tenant_id,asset_id) REFERENCES assets(tenant_id,id), ADD CONSTRAINT passport_entries_tenant_provider_fk FOREIGN KEY(tenant_id,provider_organization_id) REFERENCES organizations(tenant_id,id);
