ALTER TABLE document_share_grants DROP CONSTRAINT document_share_grants_document_id_fkey, DROP CONSTRAINT document_share_grants_issued_to_customer_id_fkey, DROP CONSTRAINT document_share_grants_issued_to_organization_id_fkey, ADD CONSTRAINT document_shares_tenant_document_fk FOREIGN KEY(tenant_id,document_id) REFERENCES documents(tenant_id,id), ADD CONSTRAINT document_shares_tenant_customer_fk FOREIGN KEY(tenant_id,issued_to_customer_id) REFERENCES customers(tenant_id,id), ADD CONSTRAINT document_shares_tenant_organization_fk FOREIGN KEY(tenant_id,issued_to_organization_id) REFERENCES organizations(tenant_id,id);
